      }
    ]
  }
}
```

---

SAGA DEFINITION:

```json
{
  "saga": {
    "saga_id": "{{idempotency_key}}",
    "steps": [
      {
        "step_id": "step_1",
        "action": {
          "system": "salesforce",
          "operation": "update_deal",
          "endpoint": "PATCH /services/data/v58.0/sobjects/Opportunity/{{deal_id}}",
          "payload": {
            "StageName": "Closed Won",
            "CloseDate": "{{closed_at}}",
            "Onboarding_Status__c": "In Progress"
          },
          "idempotency": {
            "key": "{{saga_id}}-crm-update",
            "check_before": "SELECT StageName FROM Opportunity WHERE Id = '{{deal_id}}'",
            "skip_if": "StageName == 'Closed Won'"
          }
        },
        "compensation": {
          "operation": "revert_deal_status",
          "endpoint": "PATCH /services/data/v58.0/sobjects/Opportunity/{{deal_id}}",
          "payload": {
            "StageName": "Negotiation",
            "Onboarding_Status__c": "Not Started"
          }
        },
        "timeout_ms": 10000,
        "retry": {"max_attempts": 3, "backoff": "exponential"}
      },
      {
        "step_id": "step_2",
        "action": {
          "system": "asana",
          "operation": "create_project",
          "endpoint": "POST /projects",
          "payload": {
            "name": "Onboarding: {{customer.name}}",
            "workspace": "{{ASANA_WORKSPACE_ID}}",
            "team": "{{ASANA_ONBOARDING_TEAM_ID}}",
            "notes": "Deal: {{deal_id}}\nValue: ${{deal_value}}\nOwner: {{customer.owner}}",
            "custom_fields": {
              "customer_id": "{{customer.id}}",
              "deal_id": "{{deal_id}}"
            }
          },
          "idempotency": {
            "key": "{{saga_id}}-project-create",
            "check_before": "GET /projects?workspace={{workspace}}&custom_field_deal_id={{deal_id}}",
            "skip_if": "results.length > 0",
            "use_existing": "results[0].gid"
          },
          "store_result": "project_id"
        },
        "compensation": {
          "operation": "archive_project",
          "endpoint": "PUT /projects/{{project_id}}",
          "payload": {"archived": true},
          "condition": "project_id != null"
        },
        "timeout_ms": 15000,
        "retry": {"max_attempts": 2, "backoff": "linear"}
      },
      {
        "step_id": "step_3",
        "action": {
          "system": "google_calendar",
          "operation": "create_event",
          "endpoint": "POST /calendar/v3/calendars/primary/events",
          "payload": {
            "summary": "Kickoff: {{customer.name}} Onboarding",
            "description": "Project: {{project_id}}\nDeal: {{deal_id}}",
            "start": {
              "dateTime": "{{next_business_day}}T10:00:00",
              "timeZone": "America/New_York"
            },
            "end": {
              "dateTime": "{{next_business_day}}T11:00:00",
              "timeZone": "America/New_York"
            },
            "attendees": [
              {"email": "{{customer.email}}"},
              {"email": "{{customer.owner}}"},
              {"email": "onboarding@company.com"}
            ],
            "extendedProperties": {
              "private": {
                "saga_id": "{{saga_id}}",
                "deal_id": "{{deal_id}}"
              }
            }
          },
          "store_result": "meeting_id"
        },
        "compensation": {
          "operation": "delete_event",
          "endpoint": "DELETE /calendar/v3/calendars/primary/events/{{meeting_id}}",
          "condition": "meeting_id != null"
        },
        "timeout_ms": 10000
      },
      {
        "step_id": "step_4",
        "action": {
          "system": "sendgrid",
          "operation": "send_email",
          "endpoint": "POST /v3/mail/send",
          "payload": {
            "personalizations": [{
              "to": [{"email": "{{customer.email}}", "name": "{{customer.name}}"}],
              "dynamic_template_data": {
                "customer_name": "{{customer.name}}",
                "project_link": "https://app.asana.com/0/{{project_id}}",
                "meeting_time": "{{meeting_time}}",
                "owner_name": "{{owner_first_name}}"
              }
            }],
            "from": {"email": "onboarding@company.com"},
            "template_id": "d-welcome-template-id",
            "custom_args": {
              "saga_id": "{{saga_id}}"
            }
          }
        },
        "compensation": {
          "operation": "send_cancellation_email",
          "note": "Cannot unsend email, send apology/correction instead",
          "endpoint": "POST /v3/mail/send",
          "payload": {
            "template_id": "d-cancellation-template-id"
          },
          "condition": "compensation_reason != 'email_failed'"
        },
        "timeout_ms": 5000
      }
    ]
  }
}
```

---

FAILURE SCENARIOS & COMPENSATION:

```json
{
  "failure_handling": {
    "scenario_1": {
      "failure_point": "step_3 (calendar)",
      "steps_completed": ["step_1", "step_2"],
      "compensation_order": ["step_2", "step_1"],
      "actions": [
        "Archive Asana project",
        "Revert CRM deal status to Negotiation"
      ],
      "final_state": "rolled_back",
      "alert": "ops_team"
    },
    "scenario_2": {
      "failure_point": "step_4 (email)",
      "steps_completed": ["step_1", "step_2", "step_3"],
      "compensation_strategy": "partial_complete",
      "actions": [
        "Mark workflow as 'email_failed'",
        "Queue for manual email send",
        "Do NOT rollback project/meeting"
      ],
      "reason": "Project and meeting are valuable even without welcome email"
    },
    "scenario_3": {
      "failure_point": "step_2 (asana) after retries",
      "steps_completed": ["step_1"],
      "compensation_order": ["step_1"],
      "fallback": {
        "action": "create_manual_task",
        "system": "internal_queue",
        "payload": {
          "type": "manual_onboarding_setup",
          "deal_id": "{{deal_id}}",
          "reason": "Asana integration failed"
        }
      }
    }
  }
}
```

